from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of Triple objects about an artist into a single fluent sentence.
    Handles a variety of predicates with simple natural‑language templates.
    """
    if not triples:
        return ""

    # Group triples by subject to build richer sentences
    from collections import defaultdict

    subj_map: dict[str, list[Triple]] = defaultdict(list)
    for t in triples:
        subj_map[t.subject].append(t)

    def clause(p: str, o: str) -> str:
        """Return a natural‑language clause for a predicate‑object pair."""
        if p == "birthDate":
            return f"was born on {o}"
        if p == "birthYear":
            return f"was born in {o}"
        if p == "deathDate":
            return f"died on {o}"
        if p == "deathPlace":
            return f"died in {o}"
        if p == "origin":
            return f"is from {o}"
        if p == "nationality":
            return f"is {o}"
        if p == "genre":
            return f"performs {o}"
        if p == "instrument":
            return f"plays the {o}"
        if p == "occupation":
            return f"works as {o}"
        if p == "recordLabel":
            return f"is signed to {o}"
        if p == "associatedBand/associatedMusicalArtist":
            return f"is associated with {o}"
        if p == "background":
            return f"has a background as {o}"
        if p == "activeYearsStartYear":
            return f"started their career in {o}"
        if p == "activeYearsEndYear":
            return f"ended their active years in {o}"
        # Fallback generic phrasing
        return f"{p} {o}"

    sentences: list[str] = []
    for subject, tlist in subj_map.items():
        clauses = [clause(t.predicate, t.object) for t in tlist]
        if len(clauses) == 1:
            sentences.append(f"{subject} {clauses[0]}")
        else:
            # Join multiple clauses with commas and an 'and' before the last one
            body = ", ".join(clauses[:-1]) + f", and {clauses[-1]}"
            sentences.append(f"{subject} {body}")

    final_sentence = " ".join(sentences) + "."
    # Capitalise the first character of the whole output
    return final_sentence[0].upper() + final_sentence[1:]

# EVOLVE-BLOCK-END

